css:
/* 猫咪手账主题 - 稳定移动版 */

/* 导入字体 */
@import url('https://fonts.googleapis.com/css2?family=Ma+Shan+Zheng&family=ZCOOL+XiaoWei&family=Noto+Serif+SC:wght@400;500;600&family=Long+Cang&family=ZCOOL+KuaiLe&family=ZCOOL+QingKe+HuangYou&family=Zhi+Mang+Xing&family=Liu+Jian+Mao+Cao&display=swap');

/* 全局背景和基础样式 */
body {
  background-color: #f8f3e9; /* 米色背景，类似手账纸 */
  color: #8c7e6b; /* 棕色文字，类似图片中的文字颜色 */
  font-family: "Noto Serif SC", "ZCOOL XiaoWei", serif;
  line-height: 1.8;
  position: relative;
  background-image: url('data:image/svg+xml;utf8,<svg width="100" height="100" xmlns="http://www.w3.org/2000/svg"><path d="M0,0 L100,0 L100,100 L0,100 Z" fill="none" stroke="%23e0d7c7" stroke-width="0.5" stroke-dasharray="2,2"/></svg>');
  background-size: 20px 20px;
  transition: background-color 0.5s ease;
}

/* 页面顶部的猫咪装饰 - 添加动画 */
body::before {
  content: "";
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 30px;
  background-image: url('data:image/svg+xml;utf8,<svg width="80" height="30" xmlns="http://www.w3.org/2000/svg"><path d="M0,25 Q10,10 20,25 Q30,40 40,25 Q50,10 60,25 Q70,40 80,25" fill="none" stroke="%23a99d8a" stroke-width="2"/><circle cx="20" cy="20" r="8" fill="%23f8f3e9" stroke="%23a99d8a" stroke-width="1.5"/><circle cx="60" cy="20" r="8" fill="%23f8f3e9" stroke="%23a99d8a" stroke-width="1.5"/><circle cx="18" cy="18" r="2" fill="%23a99d8a"/><circle cx="22" cy="18" r="2" fill="%23a99d8a"/><circle cx="58" cy="18" r="2" fill="%23a99d8a"/><circle cx="62" cy="18" r="2" fill="%23a99d8a"/></svg>');
  background-repeat: repeat-x;
  z-index: 100;
  pointer-events: none;
  animation: waveCat 15s linear infinite;
}

/* 猫咪波浪动画 */
@keyframes waveCat {
  0% { background-position: 0px 0px; }
  100% { background-position: 160px 0px; }
}

body::after {
  content: "";
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 30px;
  background-image: url('data:image/svg+xml;utf8,<svg width="80" height="30" xmlns="http://www.w3.org/2000/svg"><path d="M0,5 Q10,20 20,5 Q30,-10 40,5 Q50,20 60,5 Q70,-10 80,5" fill="none" stroke="%23a99d8a" stroke-width="2"/><circle cx="20" cy="10" r="8" fill="%23f8f3e9" stroke="%23a99d8a" stroke-width="1.5"/><circle cx="60" cy="10" r="8" fill="%23f8f3e9" stroke="%23a99d8a" stroke-width="1.5"/><circle cx="18" cy="8" r="2" fill="%23a99d8a"/><circle cx="22" cy="8" r="2" fill="%23a99d8a"/><circle cx="58" cy="8" r="2" fill="%23a99d8a"/><circle cx="62" cy="8" r="2" fill="%23a99d8a"/></svg>');
  background-repeat: repeat-x;
  z-index: 100;
  pointer-events: none;
  animation: waveCat 15s linear infinite reverse;
}

/* 聊天容器 - 添加阴影动画 */
#chat {
  background-color: rgba(255, 250, 240, 0.8);
  border-radius: 12px;
  box-shadow: 0 4px 12px rgba(140, 126, 107, 0.1);
  position: relative;
  border: 1px solid rgba(140, 126, 107, 0.2);
  margin: 30px auto;
  padding: 15px;
  transition: box-shadow 0.3s ease, transform 0.3s ease;

  /* 新增宽度限制 */
  max-width:802px;  /* 控制消息框最大宽度 */
  width: 100%;        /* 移动端自适应 */
}

#chat:hover {
  box-shadow: 0 8px 24px rgba(140, 126, 107, 0.2);
  transform: translateY(-3px);
}

#chat:hover {
  box-shadow: 0 8px 24px rgba(140, 126, 107, 0.2);
  transform: translateY(-3px);
}

/* 猫咪手账风格的消息框 - 用户消息 */
.mes[is_user="true"] {
  background-color: #faf5ed; /* 浅米色背景 */
  border: none;
  border-radius: 0;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);
  margin: 30px 0;
  padding: 20px 15px 15px;
  position: relative;
  overflow: visible;

  /* 圆角矩形边框 */
  border: 1.5px solid #b5a89a;
  border-radius: 12px;

  /* 添加动画效果 - 移除旋转 */
  transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), 
              box-shadow 0.4s ease, 
              background-color 0.4s ease;
}

/* 用户消息胶带效果 - 添加动画 */
.mes[is_user="true"]::before {
  content: "";
  position: absolute;
  top: -15px;
  left: 20px;
  width: 40px;
  height: 30px;
  background-color: rgba(181, 168, 154, 0.6); /* 半透明棕色 */
  transform: rotate(-3deg);
  z-index: 2;
  mask-image: url('data:image/svg+xml;utf8,<svg width="40" height="30" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="40" height="30" rx="2" ry="2" fill="black"/></svg>');
  -webkit-mask-image: url('data:image/svg+xml;utf8,<svg width="40" height="30" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="40" height="30" rx="2" ry="2" fill="black"/></svg>');

  /* 添加动画效果 */
  transition: transform 0.4s ease, background-color 0.4s ease;
}

/* 用户消息悬浮效果 - 更明显的互动但不倾斜 */
.mes[is_user="true"]:hover {
  transform: translateY(-7px);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);
  background-color: #fcf9f3;
  z-index: 10;
}

.mes[is_user="true"]:hover::before {
  transform: rotate(-6deg) translateY(-2px);
  background-color: rgba(181, 168, 154, 0.8);
}

/* 用户消息激活状态 */
.mes[is_user="true"]:active {
  transform: translateY(-2px) scale(0.98);
  transition: transform 0.1s;
}

/* 猫咪手账风格的消息框 - AI消息 */
.mes[is_user="false"] {
  background-color: #f2e9dc; /* 不同的背景色，更明显的区分 */
  border: none;
  border-radius: 0;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);
  margin: 30px 0;
  padding: 20px 15px 15px;
  position: relative;
  overflow: visible;

  /* 圆角矩形边框 */
  border: 1.5px solid #b5a89a;
  border-radius: 12px;

  /* 添加动画效果 - 移除旋转 */
  transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), 
              box-shadow 0.4s ease, 
              background-color 0.4s ease;
}

/* AI消息胶带效果 - 添加动画 */
.mes[is_user="false"]::before {
  content: "";
  position: absolute;
  bottom: -15px;
  right: 20px;
  width: 40px;
  height: 30px;
  background-color: rgba(181, 168, 154, 0.6); /* 半透明棕色 */
  transform: rotate(3deg);
  z-index: 2;
  mask-image: url('data:image/svg+xml;utf8,<svg width="40" height="30" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="40" height="30" rx="2" ry="2" fill="black"/></svg>');
  -webkit-mask-image: url('data:image/svg+xml;utf8,<svg width="40" height="30" xmlns="http://www.w3.org/2000/svg"><rect x="0" y="0" width="40" height="30" rx="2" ry="2" fill="black"/></svg>');

  /* 添加动画效果 */
  transition: transform 0.4s ease, background-color 0.4s ease;
}

/* AI消息悬浮效果 - 更明显的互动但不倾斜 */
.mes[is_user="false"]:hover {
  transform: translateY(-7px);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.1);
  background-color: #f8f0e3;
  z-index: 10;
}

.mes[is_user="false"]:hover::before {
  transform: rotate(6deg) translateY(-2px);
  background-color: rgba(181, 168, 154, 0.8);
}

/* AI消息激活状态 */
.mes[is_user="false"]:active {
  transform: translateY(-2px) scale(0.98);
  transition: transform 0.1s;
}

/* 消息文本 - 添加渐入动画 */
.mes_text {
  animation: fadeIn 0.6s ease-out;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* 新消息出现动画 */
.mes:last-child {
  animation: newMessage 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

@keyframes newMessage {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

/* 消息发送时间样式 */
.mes_timer {
  color: #b5a89a !important; /* 浅棕色 */
  font-size: 0.8em !important;
  font-family: "ZCOOL XiaoWei", sans-serif !important;
  position: absolute;
  top: 5px;
  right: 15px;
  opacity: 0.7;
  transition: opacity 0.3s ease, transform 0.3s ease;
}

.mes:hover .mes_timer {
  opacity: 1;
  transform: scale(1.05);
}

/* 头像样式 - 添加动画 */
.avatar {
  border-radius: 50%;
  box-shadow: 0 3px 6px rgba(0, 0, 0, 0.1);
  position: relative;
  transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), 
              box-shadow 0.4s ease;
  z-index: 5;
  border: 2px solid #b5a89a;
}

.avatar:hover {
  transform: scale(1.2);
  box-shadow: 0 8px 15px rgba(0, 0, 0, 0.15);
}

/* 添加头像点击效果 */
.avatar:active {
  transform: scale(0.9);
  transition: transform 0.1s;
}

/* ===== 特殊文本样式 ===== */

/* 引用样式 - 蓝色主题，添加更明显的动画 */
blockquote {
  background-color: rgba(230, 240, 255, 0.6);
  border-left: none;
  border-radius: 10px;
  color: #2961a5;
  margin: 20px 0;
  padding: 18px 22px;
  position: relative;
  font-family: "Liu Jian Mao Cao", cursive;
  font-size: 1.2em;
  line-height: 1.6;
  letter-spacing: 0.5px;
  box-shadow: 0 2px 5px rgba(41, 97, 165, 0.1);

  /* 手账风格边框 */
  border: 1.5px dashed #5e90c9;

  /* 添加动画 */
  transition: transform 0.4s ease, 
              box-shadow 0.4s ease, 
              background-color 0.4s ease;
}

/* 引用装饰 - 手账风格胶带 */
blockquote::before {
  content: "";
  position: absolute;
  top: -12px;
  left: 15px;
  width: 35px;
  height: 25px;
  background-color: rgba(94, 144, 201, 0.5);
  transform: rotate(-4deg);
  z-index: 2;
  border-radius: 2px;
  transition: transform 0.4s ease, background-color 0.4s ease;
}

/* 引用交互效果 - 更明显 */
blockquote:hover {
  transform: translateY(-5px);
  box-shadow: 0 8px 15px rgba(41, 97, 165, 0.2);
  background-color: rgba(230, 240, 255, 0.85);
}

blockquote:hover::before {
  transform: rotate(-8deg) translateY(-3px);
  background-color: rgba(94, 144, 201, 0.7);
}

/* 引用激活效果 */
blockquote:active {
  transform: translateY(-2px) scale(0.98);
  transition: transform 0.1s;
}

/* 行内代码样式 - 黄色主题，添加更明显的动画 */
code {
  background-color: rgba(255, 248, 225, 0.8);
  color: #b7801c;
  padding: 0.2em 0.6em;
  border-radius: 5px;
  font-size: 0.95em;
  font-family: "ZCOOL KuaiLe", monospace;
  position: relative;
  display: inline-block;
  margin: 0 3px;
  font-weight: 500;
  letter-spacing: 0.3px;

  /* 手账风格边框 */
  border: 1.5px dashed #e5c064;

  /* 添加动画 */
  transition: transform 0.3s ease, 
              box-shadow 0.3s ease, 
              background-color 0.3s ease;
}

/* 代码交互效果 - 更明显但不倾斜 */
code:hover {
  transform: translateY(-3px);
  box-shadow: 0 5px 10px rgba(183, 128, 28, 0.2);
  background-color: rgba(255, 248, 225, 0.95);
}

/* 代码激活效果 */
code:active {
  transform: translateY(-1px) scale(0.98);
  transition: transform 0.1s;
}

/* 代码块样式 - 添加更明显的动画 */
pre {
  background-color: rgba(255, 248, 225, 0.8);
  padding: 20px;
  margin: 25px 0;
  border-radius: 10px;
  overflow: auto;
  position: relative;
  box-shadow: 0 2px 5px rgba(183, 128, 28, 0.1);

  /* 手账风格边框 */
  border: 1.5px dashed #e5c064;

  /* 添加动画 */
  transition: transform 0.4s ease, 
              box-shadow 0.4s ease, 
              background-color 0.4s ease;
}

/* 代码块装饰 - 胶带效果，添加动画 */
pre::before {
  content: "{ code }";
  position: absolute;
  top: -12px;
  right: 20px;
  padding: 3px 10px;
  background-color: rgba(229, 192, 100, 0.7);
  color: white;
  font-size: 12px;
  font-family: "ZCOOL XiaoWei", sans-serif;
  border-radius: 4px;
  transform: rotate(2deg);
  z-index: 2;
  transition: transform 0.4s ease, background-color 0.4s ease;
}

/* 代码块交互效果 - 更明显但不倾斜 */
pre:hover {
  transform: translateY(-5px);
  box-shadow: 0 8px 16px rgba(183, 128, 28, 0.2);
  background-color: rgba(255, 248, 225, 0.9);
}

pre:hover::before {
  transform: rotate(4deg) translateY(-2px);
  background-color: rgba(229, 192, 100, 0.9);
}

/* 代码块激活效果 */
pre:active {
  transform: translateY(-2px) scale(0.99);
  transition: transform 0.1s;
}

pre code {
  background: transparent;
  border: none;
  padding: 0;
  font-size: 0.95em;
  color: #b7801c;
  line-height: 1.6;
  display: block;
  box-shadow: none;
  transform: none;
}

pre:hover code {
  transform: none;
}

/* 粗体样式 - 黑色主题，添加更明显的动画 */
strong, b {
  color: #333333;
  font-weight: 600;
  position: relative;
  padding: 0 4px;
  letter-spacing: 0.3px;
  font-family: "ZCOOL QingKe HuangYou", sans-serif;
  font-size: 1.05em;

  /* 手账风格装饰 */
  background-color: rgba(240, 240, 240, 0.6);
  border-radius: 4px;
  border-bottom: 2px dotted #666666;

  /* 添加动画 */
  transition: background-color 0.3s ease, 
              transform 0.3s ease,
              box-shadow 0.3s ease;
}

/* 粗体交互效果 - 更明显但不倾斜 */
strong:hover, b:hover {
  background-color: rgba(240, 240, 240, 0.9);
  transform: scale(1.08);
  box-shadow: 0 3px 6px rgba(0, 0, 0, 0.1);
}

/* 粗体激活效果 */
strong:active, b:active {
  transform: scale(0.95);
  transition: transform 0.1s;
}

/* 斜体样式 - 添加更明显的动画 */
em, i {
  font-family: "Zhi Mang Xing", cursive;
  font-size: 1.18em;
  color: #94b160;
  font-style: italic;
  position: relative;
  display: inline-block;
  padding: 0 3px;
  letter-spacing: 0.5px;

  /* 添加动画 */
  transition: color 0.3s ease, 
              transform 0.3s ease,
              text-shadow 0.3s ease;
}

/* 斜体装饰 - 手账风格下划线，添加动画 */
em::after, i::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 2px;
  background: rgba(148, 177, 96, 0.4);
  background-image: linear-gradient(to right, rgba(148, 177, 96, 0.4) 0%, rgba(148, 177, 96, 0.4) 50%, transparent 50%, transparent 100%);
  background-size: 6px 2px;
  opacity: 0.8;
  transition: background 0.3s ease, height 0.3s ease;
}

/* 斜体交互效果 - 更明显但减少旋转 */
em:hover, i:hover {
  color: #7b9c42;
  transform: scale(1.08);
  text-shadow: 1px 1px 3px rgba(123, 156, 66, 0.2);
}

em:hover::after, i:hover::after {
  height: 3px;
  background-image: linear-gradient(to right, rgba(123, 156, 66, 0.7) 0%, rgba(123, 156, 66, 0.7) 50%, transparent 50%, transparent 100%);
}

/* 斜体激活效果 */
em:active, i:active {
  transform: scale(0.95);
  transition: transform 0.1s;
}

/* 标题样式 - 使用手账风格，添加更明显的动画 */
h1, h2, h3 {
  font-family: "Ma Shan Zheng", "Noto Serif SC", serif;
  color: #94b160;
  position: relative;
  transition: transform 0.4s ease, 
              color 0.4s ease,
              text-shadow 0.4s ease;
}

h1 {
  font-size: 1.9em;
  border-bottom: none;
  padding-bottom: 10px;
  margin: 1.8em 0 1em;
  text-align: center;
}

/* 标题1装饰 - 手账风格装饰线，添加动画 */
h1::before, h1::after {
  content: "";
  position: absolute;
  bottom: 0;
  width: 30%;
  height: 2px;
  background-image: linear-gradient(to right, rgba(148, 177, 96, 0.6) 0%, rgba(148, 177, 96, 0.6) 50%, transparent 50%, transparent 100%);
  background-size: 8px 2px;
  transition: width 0.4s ease, 
              background-image 0.4s ease;
}

h1::before {
  left: 0;
}

h1::after {
  right: 0;
}

/* 标题1交互效果 - 更明显 */
h1:hover {
  transform: translateY(-3px);
  color: #7b9c42;
  text-shadow: 0 3px 6px rgba(123, 156, 66, 0.2);
}

h1:hover::before, h1:hover::after {
  width: 40%;
  background-image: linear-gradient(to right, rgba(123, 156, 66, 0.8) 0%, rgba(123, 156, 66, 0.8) 50%, transparent 50%, transparent 100%);
}

h2 {
  font-size: 1.6em;
  border-left: none;
  padding-left: 20px;
  margin: 1.5em 0 0.8em;
  position: relative;
}

/* 标题2装饰 - 手账风格胶带，添加动画 */
h2::before {
  content: "";
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 12px;
  height: 28px;
  background-color: rgba(148, 177, 96, 0.6);
  border-radius: 2px;
  transition: width 0.4s ease, 
              background-color 0.4s ease;
}

/* 标题2交互效果 - 更明显 */
h2:hover {
  transform: translateX(5px);
  color: #7b9c42;
  text-shadow: 0 2px 4px rgba(123, 156, 66, 0.2);
}

h2:hover::before {
  width: 18px;
  background-color: rgba(123, 156, 66, 0.8);
}

h3 {
  font-size: 1.4em;
  border-bottom: none;
  padding-bottom: 5px;
  margin: 1.2em 0 0.7em;
}

/* 标题3装饰 - 手账风格下划线，添加动画 */
h3::after {
  content: "";
  display: block;
  width: 100%;
  height: 2px;
  background-image: linear-gradient(to right, rgba(148, 177, 96, 0.5) 0%, rgba(148, 177, 96, 0.5) 50%, transparent 50%, transparent 100%);
  background-size: 4px 2px;
  margin-top: 5px;
  transition: background-image 0.4s ease, height 0.4s ease;
}

/* 标题3交互效果 - 更明显 */
h3:hover {
  transform: translateY(-2px);
  color: #7b9c42;
  text-shadow: 0 2px 4px rgba(123, 156, 66, 0.15);
}

h3:hover::after {
  height: 3px;
  background-image: linear-gradient(to right, rgba(123, 156, 66, 0.7) 0%, rgba(123, 156, 66, 0.7) 50%, transparent 50%, transparent 100%);
}

h4, h5, h6 {
  font-family: "ZCOOL XiaoWei", "Noto Serif SC", serif;
  color: #94b160;
  transition: transform 0.3s ease, 
              color 0.3s ease,
              text-shadow 0.3s ease;
}

h4:hover, h5:hover, h6:hover {
  transform: translateY(-2px);
  color: #7b9c42;
  text-shadow: 0 2px 3px rgba(123, 156, 66, 0.1);
}

/* 滚动条 - 美化 */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  background: rgba(255, 248, 220, 0.5);
  border-radius: 5px;
}

::-webkit-scrollbar-thumb {
  background: #b5a89a;
  border-radius: 5px;
  border: 2px solid rgba(255, 248, 220, 0.5);
  transition: background 0.3s ease;
}

::-webkit-scrollbar-thumb:hover {
  background: #a99d8a;
}

/* 表格样式 - 手账风格，添加更明显的动画 */
table {
  border-collapse: collapse;
  width: 100%;
  margin: 25px 0;
  background-color: rgba(255, 255, 255, 0.7);
  border-radius: 10px;
  overflow: hidden;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.05);
  border: 1.5px dashed rgba(181, 168, 154, 1);
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
}

th, td {
  padding: 12px 15px;
  border-bottom: 1px dashed rgba(181, 168, 154, 0.3);
  text-align: left;
}

th {
