  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  background: rgba(255, 248, 220, 0.5);
  border-radius: 5px;
}

::-webkit-scrollbar-thumb {
  background: rgba(181, 168, 154, 1);
  border-radius: 5px;
  border: 2px solid rgba(255, 248, 220, 0.5);
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(169, 157, 138, 1);
}

